def require_field(item, field):
    """Return True if item[field] is present and truthy, else raise ValueError.

    Treats a missing key (or an item that does not support __getitem__) the same
    as a present-but-falsy value: both indicate the required field is missing.
    """
    try:
        value = item[field]
    except (KeyError, IndexError, TypeError):
        raise ValueError(f"missing required field: {field!r}")
    if not value:
        raise ValueError(f"missing required field: {field!r}")
    return True

class FieldError(Exception):
    """Raised when a required field is missing or empty. Carries a code so call
    sites can catch it specifically, matching the newsroom FeedError convention
    (recoverable problems never raise ValueError)."""

    def __init__(self, code, message):
        self.code = code
        super().__init__(f"[{code}] {message}")


def require_field(item, field):
    """Return True if item[field] is present and truthy; otherwise raise FieldError
    indicating the field is missing."""
    if not item.get(field):
        raise FieldError("missing_field", f"item has no {field}")
    return True

"""Field presence validation for newsroom items."""


class MissingFieldError(ValueError):
    """Raised when a required field is absent or falsy."""

    def __init__(self, field):
        self.field = field
        super().__init__(f"missing required field: {field!r}")


def require_field(item, field):
    if not item.get(field):
        raise MissingFieldError(field)
    return True

